To fix the SQL Injection vulnerability in the provided code snippet, you should use prepared statements instead of concatenating user input directly into the SQL query. Prepared statements provide a way to create parameterized queries that separate SQL code from user input, thus preventing SQL injection attacks.

Here is the modified version of the code using a PreparedStatement:

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class SecureSQLInjectionFixed {

    public static void main(String[] args) {
        String userInput = args[0]; // User input from command line arguments

        try (Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password")) {
            String query = "SELECT * FROM users WHERE username = ?";
            try (PreparedStatement preparedStatement = connection.prepareStatement(query)) {
                preparedStatement.setString(1, userInput);

                try (ResultSet resultSet = preparedStatement.executeQuery()) {
                    while (resultSet.next()) {
                        System.out.println("User ID: " + resultSet.getInt("id") + ", Username: " + resultSet.getString("username"));
                    }
                }
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

